const config = $('Set Configuration1').first().json;
const mode = config.generation_mode || '';
const numScenes = config.num_scenes || 5;
const customScenes = config.custom_scenes || '';
const presetCollection = config.preset_collection || '';
const aiPrompt = config.ai_prompt || '';

// PRESET COLLECTIONS
const presets = {
  '80s Action Legends': [
    { celebrity: 'Arnold Schwarzenegger as the T-800', movie: 'Terminator 2', costume: 'black leather biker jacket, battle damage showing chrome', location: 'the industrial steel mill with molten sparks', gesture: 'thumbs-up', era: '1991 sci-fi action' },
    { celebrity: 'Sylvester Stallone as Rocky Balboa', movie: 'Rocky IV', costume: 'boxing shorts and gloves, sweaty', location: 'the boxing ring in Moscow', gesture: 'fist pump', era: '1985 sports drama' },
    { celebrity: 'Bruce Willis as John McClane', movie: 'Die Hard', costume: 'dirty white tank top, barefoot', location: 'the Nakatomi Plaza lobby with shattered glass', gesture: 'smirking', era: '1988 action thriller' },
    { celebrity: 'Harrison Ford as Indiana Jones', movie: 'Raiders of the Lost Ark', costume: 'iconic fedora hat, leather jacket, whip', location: 'ancient temple with golden idol', gesture: 'tipping hat', era: '1981 adventure' }
  ],
  '90s Blockbusters': [
    { celebrity: 'Leonardo DiCaprio as Jack Dawson', movie: 'Titanic', costume: 'suspenders, white shirt', location: 'the bow of the Titanic ship', gesture: 'arms spread wide', era: '1997 romance drama' },
    { celebrity: 'Keanu Reeves as Neo', movie: 'The Matrix', costume: 'long black trench coat, sunglasses', location: 'the lobby with marble columns', gesture: 'come here hand motion', era: '1999 cyberpunk' },
    { celebrity: 'Tom Hanks as Forrest Gump', movie: 'Forrest Gump', costume: 'checkered shirt, khaki pants', location: 'park bench with box of chocolates', gesture: 'friendly wave', era: '1994 drama' },
    { celebrity: 'Will Smith as Agent J', movie: 'Men in Black', costume: 'black suit, sunglasses, neuralyzer', location: 'MIB headquarters with alien screens', gesture: 'pointing neuralyzer', era: '1997 sci-fi comedy' }
  ],
  'Marvel Cinematic Universe Heroes': [
    { celebrity: 'Robert Downey Jr. as Tony Stark/Iron Man', movie: 'The Avengers', costume: 'Iron Man Mark VII armor, faceplate up', location: 'Stark Tower with New York skyline', gesture: 'peace sign', era: '2012 superhero' },
    { celebrity: 'Chris Evans as Steve Rogers/Captain America', movie: 'Avengers: Endgame', costume: 'classic Cap suit with shield', location: 'Avengers compound', gesture: 'salute', era: '2019 superhero' },
    { celebrity: 'Scarlett Johansson as Natasha Romanoff/Black Widow', movie: 'Black Widow', costume: 'white tactical suit', location: 'Red Room training facility', gesture: 'confident stance', era: '2021 action' },
    { celebrity: 'Chris Hemsworth as Thor', movie: 'Thor: Ragnarok', costume: 'gladiator armor, short hair', location: 'Sakaar arena with neon lights', gesture: 'hammer raised', era: '2017 sci-fi comedy' }
  ],
  'Star Wars Saga Characters': [
    { celebrity: 'Harrison Ford as Han Solo', movie: 'Star Wars: A New Hope', costume: 'white shirt, black vest, blaster holster', location: 'Millennium Falcon cockpit', gesture: 'cocky grin', era: '1977 space opera' },
    { celebrity: 'Carrie Fisher as Princess Leia', movie: 'Star Wars: A New Hope', costume: 'iconic white gown, hair buns', location: 'Death Star detention block', gesture: 'crossed arms', era: '1977 space opera' },
    { celebrity: 'Mark Hamill as Luke Skywalker', movie: 'Return of the Jedi', costume: 'black Jedi robes', location: 'Endor forest with Ewoks', gesture: 'lightsaber pose', era: '1983 space opera' },
    { celebrity: 'Daisy Ridley as Rey', movie: 'The Force Awakens', costume: 'desert scavenger outfit, staff', location: 'Jakku desert with fallen Star Destroyer', gesture: 'determined look', era: '2015 space opera' }
  ]
};

function parseCustomScenes(customText) {
  if (!customText || !customText.trim()) return [];
  const lines = customText.split('\n').filter(line => line.trim() && line.includes('|'));
  return lines.map((line, index) => {
    const parts = line.split('|').map(p => p.trim());
    return {
      scene_id: index + 1,
      celebrity: parts[0] || 'Celebrity',
      movie: parts[1] || 'Movie',
      era: parts[2] || 'Unknown era',
      location: parts[3] || 'iconic movie set',
      costume: parts[4] || 'their iconic costume',
      gesture: parts[5] || 'friendly pose'
    };
  });
}

let scenes = [];

if (mode.includes('Custom')) {
  scenes = parseCustomScenes(customScenes);
} else if (mode.includes('Presets')) {
  for (const [key, value] of Object.entries(presets)) {
    if (presetCollection.includes(key) || key.includes(presetCollection.split('(')[0].trim())) {
      scenes = value.map((s, i) => ({ ...s, scene_id: i + 1 }));
      break;
    }
  }
  if (scenes.length === 0) {
    scenes = presets['80s Action Legends'].map((s, i) => ({ ...s, scene_id: i + 1 }));
  }
} else {
  const prompt = (aiPrompt || '').toLowerCase();
  if (prompt.includes('80s') || prompt.includes('action')) {
    scenes = presets['80s Action Legends'];
  } else if (prompt.includes('marvel') || prompt.includes('superhero')) {
    scenes = presets['Marvel Cinematic Universe Heroes'];
  } else if (prompt.includes('star wars') || prompt.includes('jedi')) {
    scenes = presets['Star Wars Saga Characters'];
  } else {
    scenes = presets['90s Blockbusters'];
  }
  scenes = scenes.map((s, i) => ({ ...s, scene_id: i + 1 }));
}

scenes = scenes.slice(0, numScenes);
scenes = scenes.map((s, i) => ({ ...s, scene_id: i + 1 }));

console.log('Generated ' + scenes.length + ' scenes');

return scenes.map(scene => ({ json: scene }));

const scene = $input.item.json;
const config = $('Set Configuration1').first().json;
const userPhotoUrl = config.user_photo_url || '';
const aspectRatio = config.aspect_ratio || '9:16';
const visualStyle = config.visual_style || 'Ultra-realistic (default)';

const styleModifiers = {
  'Ultra-realistic (default)': 'High-resolution photorealistic style, natural lighting, shallow depth of field, realistic skin tones.',
  'Cinematic film look': 'Cinematic film grain, dramatic lighting, anamorphic lens flare, movie poster quality.',
  'Vintage retro style': 'VHS aesthetic, warm color grading, nostalgic vintage photography style.',
  'Modern Instagram aesthetic': 'Instagram filtered look, vibrant colors, polished.'
};

const styleText = styleModifiers[visualStyle] || styleModifiers['Ultra-realistic (default)'];

// First frame prompt for this scene (Easy-Peasy.AI template)
const masterPrompt = `Ultra-realistic selfie captured strictly from a front-phone-camera perspective, with the framing and angle matching a real handheld selfie. The mobile phone itself is never visible, but the posture and composition clearly imply that I am holding it just outside the frame at arm's length. The angle remains consistent with a true selfie: slightly wide field of view, eye-level orientation, and natural arm-extension distance. The person taking the selfie looks exactly like the reference image provided. I am standing next to ${scene.celebrity}, who appears with the exact age, facial features, and look they had in '${scene.movie}'. ${scene.celebrity} is wearing ${scene.costume}. The background shows the authentic film set from '${scene.movie}', specifically ${scene.location}, including recognizable scenery, props, lighting setup, and atmosphere that match the ${scene.era}. Subtle blurred crew members and equipment may appear far behind to suggest a scene break. We both look relaxed and naturally posing between takes, with ${scene.celebrity} giving a casual ${scene.gesture}. The shot preserves a candid and natural vibe, with accurate selfie-camera distortion, cinematic lighting, shallow depth of field, and realistic skin tones. ${styleText} No phone visible in photo.`;

return {
  json: {
    ...scene,
    user_photo_url: userPhotoUrl,
    image_prompt: masterPrompt,
    aspect_ratio: aspectRatio,
    image_aspect_ratio: aspectRatio,
    visual_style: visualStyle
  }
};

// Create image pairs for Veo 3.1 FIRST_AND_LAST_FRAMES_2_VIDEO mode
const allData = $input.first().json.data || [];
const validImages = allData.filter(item => item.image_url && item.image_url.startsWith('http'));

console.log('Total images collected: ' + validImages.length);

if (validImages.length < 2) {
  throw new Error('Need at least 2 images to create seamless transitions! Got: ' + validImages.length);
}

// Sort by scene_id to ensure correct order
validImages.sort((a, b) => (a.scene_id || 0) - (b.scene_id || 0));

// Create pairs for seamless transitions:
// Pair 1: Scene 1 image → Scene 2 image (walking from set 1 to set 2)
// Pair 2: Scene 2 image → Scene 3 image (walking from set 2 to set 3)
// etc.
const pairs = [];
for (let i = 0; i < validImages.length - 1; i++) {
  pairs.push({
    pair_id: i + 1,
    first_frame_url: validImages[i].image_url,
    last_frame_url: validImages[i + 1].image_url,
    from_scene: validImages[i].scene_id,
    to_scene: validImages[i + 1].scene_id,
    from_movie: validImages[i].movie || 'Movie Set A',
    to_movie: validImages[i + 1].movie || 'Movie Set B',
    from_location: validImages[i].location || 'location A',
    to_location: validImages[i + 1].location || 'location B'
  });
}

console.log('Created ' + pairs.length + ' image pairs for Veo 3.1 transitions');
console.log('Example pair:', JSON.stringify(pairs[0], null, 2));

return pairs.map(p => ({ json: p }));

// Check Veo 3.1 Video Generation Status
// API: /api/v1/veo/record-info
// successFlag: 0=generating, 1=success, 2=failed, 3=generation failed

const videoData = $input.item.json;
const pairData = $('Loop Over Image Pairs').first().json;
const MAX_RETRIES = 120; // 120 * 3s = 6 minutes max
const retryCount = videoData.retryCount || 0;

console.log(`Veo 3.1 polling attempt: ${retryCount + 1}/${MAX_RETRIES}`);
console.log(`Pair ${pairData.pair_id}: ${pairData.from_movie} → ${pairData.to_movie}`);

if (retryCount >= MAX_RETRIES) {
  console.log('⚠️ Max retries reached, video generation timeout');
  return { 
    json: { 
      videoReady: true,
      video_url: null,
      status: 'timeout',
      reason: 'Video generation timeout after 6 minutes',
      pair_id: pairData.pair_id
    } 
  };
}

const successFlag = videoData.data?.successFlag;
const code = videoData.code;
const response = videoData.data?.response;

console.log(`API Code: ${code}, successFlag: ${successFlag}`);

// SUCCESS (successFlag = 1)
if (successFlag === 1) {
  console.log('✅ Veo 3.1 video generation complete!');

  const resultUrls = response?.resultUrls || [];
  const videoUrl = resultUrls[0] || null;

  console.log('Video URL:', videoUrl);

  return { 
    json: { 
      videoReady: true,
      video_url: videoUrl,
      status: 'success',
      pair_id: pairData.pair_id,
      from_movie: pairData.from_movie,
      to_movie: pairData.to_movie
    } 
  };
}

// FAILED (successFlag = 2 or 3)
if (successFlag === 2 || successFlag === 3) {
  console.log('❌ Veo 3.1 video generation failed');
  const errorMsg = videoData.data?.errorMessage || 'Unknown error';
  return { 
    json: { 
      videoReady: true,
      video_url: null,
      status: 'failed',
      reason: errorMsg,
      pair_id: pairData.pair_id
    } 
  };
}

// API Error
if (code && code !== 200) {
  console.log('❌ API error: code ' + code);
  return { 
    json: { 
      videoReady: true,
      video_url: null,
      status: 'api_error',
      reason: videoData.msg || 'Unknown API error',
      pair_id: pairData.pair_id
    } 
  };
}

// STILL GENERATING (successFlag = 0 or undefined)
console.log('⏳ Video still generating, will retry...');
return { 
  json: { 
    ...videoData,
    videoReady: false,
    continuePolling: true,
    retryCount: retryCount + 1,
    pair_id: pairData.pair_id
  } 
};

const videoUrl = $json.video_url;
const pairId = $json.pair_id;

if (!videoUrl || !videoUrl.startsWith('http')) {
  console.log(`Pair ${pairId}: Invalid or missing video URL, skipping`);
  return { json: { video_url: null, skipped: true, pair_id: pairId, reason: 'Invalid or missing video URL' } };
}

console.log(`Pair ${pairId}: Video ready - ${videoUrl}`);
return { json: { video_url: videoUrl, skipped: false, pair_id: pairId } };

const allData = $input.first().json.data || [];
const videoUrls = allData
  .sort((a, b) => (a.pair_id || 0) - (b.pair_id || 0))
  .map(item => item.video_url)
  .filter(url => url && typeof url === 'string' && url.startsWith('http'));

const skippedCount = allData.filter(item => item.skipped === true).length;

console.log('Total videos ready: ' + videoUrls.length);
console.log('Skipped: ' + skippedCount);

return [{
  json: {
    video_urls: videoUrls,
    count: videoUrls.length,
    skipped_count: skippedCount,
    total_transitions: allData.length
  }
}];

const mergeResult = $input.first().json;
const config = $('Set Configuration1').first().json;
const timestamp = Date.now();

if (mergeResult.success && mergeResult.video_url) {
  const fileSizeMB = mergeResult.size_bytes ? (mergeResult.size_bytes / (1024 * 1024)).toFixed(2) : 'unknown';

  return [{
    json: {
      session_id: `session_${timestamp}`,
      status: '🎬 Your Celebrity Selfie Movie is Ready!',
      merged_video_url: mergeResult.video_url,
      file_size_mb: parseFloat(fileSizeMB),
      transitions_merged: mergeResult.video_count,
      job_id: mergeResult.job_id,
      user_name: config.user_name,
      created_at: new Date().toISOString(),
      instructions: 'Download your seamless movie journey now! Link expires in 1 hour.'
    }
  }];
}

return [{
  json: {
    session_id: `session_${timestamp}`,
    status: 'Merge failed',
    error: mergeResult.error || 'Unknown merge error',
    user_name: config.user_name,
    created_at: new Date().toISOString()
  }
}];

const imgbbResponse = $json;
const prevData = $('Upload Your Photo1').first().json;

const imageUrl = imgbbResponse.data?.image?.url || imgbbResponse.data?.url || imgbbResponse.data?.display_url || '';

console.log('ImgBB Upload Result:', imageUrl ? 'SUCCESS' : 'FAILED');

return {
  json: {
    ...prevData,
    user_photo_url: imageUrl,
    imgbb_success: !!imageUrl
  }
};

const imageData = $input.item.json;
const MAX_RETRIES = 120;
const retryCount = imageData.retryCount || 0;

console.log(`Image polling attempt: ${retryCount + 1}/${MAX_RETRIES}`);

if (retryCount >= MAX_RETRIES) {
  console.log('⚠️ Max retries reached, image generation timeout');
  return { json: { skipImage: true, imageReady: false, retryCount: 0, reason: 'Image generation timeout' } };
}

const state = imageData.data?.state;

if (state === 'success') {
  console.log('✅ Image generation complete!');
  let resultUrls = [];
  try {
    if (imageData.data.resultJson) {
      const parsed = JSON.parse(imageData.data.resultJson);
      resultUrls = parsed.resultUrls || [];
    }
  } catch (e) {
    console.log('Error parsing resultJson:', e.message);
  }

  const imageUrl = resultUrls[0] || null;
  return { json: { ...imageData, skipImage: false, imageReady: true, retryCount: 0, image_url: imageUrl } };
} else if (state === 'fail') {
  console.log('❌ Image generation failed');
  return { json: { ...imageData, skipImage: true, imageReady: false, retryCount: 0, reason: 'Image generation failed' } };
}

console.log('⏳ Image still generating, will retry...');
return { json: { ...imageData, skipImage: false, imageReady: false, continuePolling: true, retryCount: retryCount + 1 } };

const sceneData = $('Generate Image Prompt1').first().json;
const imageData = $input.item.json;
const imageUrl = imageData.image_url;

console.log('=== IMAGE GENERATION COMPLETE ===');
console.log(`Scene ID: ${sceneData.scene_id}`);
console.log(`Movie: ${sceneData.movie}`);
console.log(`Image URL: ${imageUrl}`);

return {
  json: {
    success: true,
    image_url: imageUrl,
    scene_id: sceneData.scene_id,
    movie: sceneData.movie,
    location: sceneData.location || 'movie set',
    generatedAt: new Date().toISOString()
  }
};
